-- ── Migration: Submissions Table ──────────────────────────────────────────────\n-- Adds support for student project submissions and faculty grading.\n\nCREATE TABLE IF NOT EXISTS submissions (\n    id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    event_id        UUID        NOT NULL REFERENCES events(id) ON DELETE CASCADE,\n    student_id      UUID        NOT NULL REFERENCES users(id) ON DELETE CASCADE,\n    team_id         UUID        REFERENCES teams(id) ON DELETE SET NULL,\n    project_link    TEXT        NOT NULL,\n    submission_time TIMESTAMPTZ NOT NULL DEFAULT NOW(),\n    score           INTEGER     CHECK (score BETWEEN 0 AND 100),\n    feedback        TEXT,\n    status          TEXT        DEFAULT 'pending' CHECK (status IN ('pending', 'graded')),\n    \n    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),\n    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),\n\n    -- Ensure one submission per student/team per event\n    -- If team_id is null, it's an individual submission.\n    -- If team_id is present, we might want to restrict one per team, but for now we'll allow per-student as long as they are distinct.\n    CONSTRAINT uq_submission_event_student UNIQUE (event_id, student_id)\n);\n\n-- RLS for submissions\nALTER TABLE submissions ENABLE ROW LEVEL SECURITY;\n\n-- Enable SELECT for students on their own submissions\nCREATE POLICY \"submissions_select_student\" ON submissions FOR SELECT\n    USING (student_id = current_user_id() OR auth_uid = auth.uid());\n\n-- Faculty/HoD/Admin can see all submissions for events in their department\nCREATE POLICY \"submissions_select_staff\" ON submissions FOR SELECT\n    USING (\n        current_user_role() IN ('faculty', 'hod', 'admin')\n        AND EXISTS (\n            SELECT 1 FROM events e \n            WHERE e.id = submissions.event_id \n            AND (e.department_id = current_user_department() OR e.creator_id = current_user_id())\n        )\n    );\n\n-- Faculty/HoD/Admin can update submissions (grading)\nCREATE POLICY \"submissions_update_staff\" ON submissions FOR UPDATE\n    USING (\n        current_user_role() IN ('faculty', 'hod', 'admin')\n        AND EXISTS (\n            SELECT 1 FROM events e \n            WHERE e.id = submissions.event_id \n            AND (e.department_id = current_user_department() OR e.creator_id = current_user_id())\n        )\n    );
